from datetime import date
from statistics import mean, median

def summarize_orders(customer_id: str, date_from: str, date_to: str) -> dict:
    """
    Return aggregate statistics for orders in a date range.
    Never returns raw rows — use list_orders() for that.
    """
    orders = _fetch_all_orders(customer_id, date_from, date_to)
    if not orders:
        return {"customer_id": customer_id, "total_orders": 0,
                "date_from": date_from, "date_to": date_to}

    totals     = [o["total_usd"] for o in orders]
    by_status  = {}
    for o in orders:
        by_status[o["status"]] = by_status.get(o["status"], 0) + 1

    recent = sorted(orders, key=lambda o: o["date"], reverse=True)[:3]

    return {
        "customer_id": customer_id,
        "date_from": date_from,
        "date_to": date_to,
        "total_orders": len(orders),
        "total_revenue_usd": round(sum(totals), 2),
        "average_order_usd": round(mean(totals), 2),
        "median_order_usd": round(median(totals), 2),
        "max_order_usd": max(totals),
        "min_order_usd": min(totals),
        "by_status": by_status,
        "most_recent_3": [
            {"order_id": o["id"], "date": o["date"], "total_usd": o["total_usd"]}
            for o in recent
        ],
        "note": "Use list_orders(customer_id, cursor=...) to browse individual orders.",
    }

def _fetch_all_orders(customer_id, date_from, date_to):
    return [
        {"id": f"ord_{i}", "date": "2026-07-01", "total_usd": 20 + i * 3,
         "status": "shipped" if i % 3 else "returned"}
        for i in range(120)
    ]

import anthropic

_client = anthropic.Anthropic()

def summarize_support_transcript(ticket_id: str) -> dict:
    """
    Fetch a support transcript and return an AI-generated summary.
    The full transcript is consumed by a separate, short-lived model call
    and never enters the agent's main context window.
    """
    transcript = _fetch_transcript(ticket_id)
    if not transcript:
        return {"error": "NOT_FOUND", "message": f"Ticket {ticket_id} not found"}

    word_count = len(transcript.split())
    if word_count < 200:
        return {"ticket_id": ticket_id, "summary": transcript, "word_count": word_count}

    resp = _client.messages.create(
        model="claude-haiku-4-5-20251001",   # cheapest model for summarisation
        max_tokens=400,
        messages=[{
            "role": "user",
            "content": (
                "Summarise this customer support transcript in 3–5 bullet points. "
                "Include: issue reported, steps taken, resolution status, any open actions.\n\n"
                + transcript[:20000]   # cap at 20k chars to stay within Haiku's budget
            ),
        }],
    )
    summary = resp.content[0].text

    return {
        "ticket_id": ticket_id,
        "word_count": word_count,
        "summary": summary,
        "note": "Full transcript available via get_transcript_section(ticket_id, page).",
    }

def _fetch_transcript(ticket_id: str) -> str:
    return "Agent: Hello, how can I help?\nCustomer: My order hasn't arrived... " * 50

import json

SUMMARY_SCHEMA = {
    "type": "object",
    "properties": {
        "issue":      {"type": "string", "description": "One-sentence issue description"},
        "resolution": {"type": "string", "enum": ["resolved", "pending", "escalated", "no_action"]},
        "open_actions": {
            "type": "array",
            "items": {"type": "string"},
            "description": "List of follow-up actions required",
        },
        "sentiment": {"type": "string", "enum": ["positive", "neutral", "negative"]},
    },
    "required": ["issue", "resolution", "open_actions", "sentiment"],
}

def structured_transcript_summary(ticket_id: str) -> dict:
    transcript = _fetch_transcript(ticket_id)
    tools = [{
        "name": "record_summary",
        "description": "Record the structured summary of a support transcript",
        "input_schema": SUMMARY_SCHEMA,
    }]
    resp = _client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=tools,
        tool_choice={"type": "any"},
        messages=[{
            "role": "user",
            "content": f"Summarise this support transcript:\n\n{transcript[:15000]}",
        }],
    )
    for block in resp.content:
        if block.type == "tool_use" and block.name == "record_summary":
            return {"ticket_id": ticket_id, **block.input}

    return {"error": "SUMMARIZATION_FAILED", "ticket_id": ticket_id}

import pytest, json

def test_aggregate_summary_covers_all_orders(monkeypatch):
    monkeypatch.setattr(
        "__main__._fetch_all_orders",
        lambda cid, df, dt: [
            {"id": f"o{i}", "date": "2026-07-01", "total_usd": float(i + 1), "status": "shipped"}
            for i in range(100)
        ],
    )
    result = summarize_orders("cust_1", "2026-01-01", "2026-07-01")
    assert result["total_orders"] == 100
    assert result["total_revenue_usd"] == pytest.approx(5050.0)
    assert len(result["most_recent_3"]) == 3
    assert "raw" not in str(result)   # no raw row dump

def test_aggregate_summary_char_budget():
    result = summarize_orders("cust_1", "2026-01-01", "2026-07-01")
    assert len(json.dumps(result)) < 4000

